import{_ as i,o as a,c as o,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Selección de equipo","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/equipment-selection.md","filePath":"es/power-systems/equipment-selection.md"}'),l={name:"es/power-systems/equipment-selection.md"};function n(c,e,r,t,d,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="seleccion-de-equipo" tabindex="-1">Selección de equipo <a class="header-anchor" href="#seleccion-de-equipo" aria-label="Permalink to &quot;Selección de equipo&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La selección de equipo en sistemas de potencia implica elegir componentes que cumplan con los requisitos eléctricos, operativos y ambientales de una instalación.</p><p>Esto incluye la selección de dispositivos como transformadores, switchgear (celdas de media tensión), tableros de distribución, dispositivos de protección y equipo de distribución.</p><p>Una selección adecuada asegura que el sistema opere de manera segura, confiable y eficiente bajo todas las condiciones esperadas.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la selección de equipo es:</p><ul><li>Ajustar las capacidades del equipo a los requisitos del sistema</li><li>Asegurar operación segura bajo condiciones normales y de falla</li><li>Optimizar el desempeño, el costo y la confiabilidad</li><li>Apoyar la expansión futura y la flexibilidad del sistema</li></ul><p>Una selección incorrecta puede provocar fallas, riesgos de seguridad y modificaciones costosas.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La selección de equipo se basa en analizar los requisitos del sistema y compararlos con las capacidades y características del equipo.</p><p>Los pasos clave incluyen:</p><ul><li>Definir los niveles de voltaje y la configuración del sistema</li><li>Calcular la demanda de carga y la diversidad</li><li>Determinar la corriente de cortocircuito disponible</li><li>Identificar las condiciones ambientales y de instalación</li><li>Seleccionar las capacidades del equipo y las características de protección</li></ul><p>Cada componente debe ser compatible tanto con los elementos aguas arriba como aguas abajo.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La selección de equipo es necesaria en:</p><ul><li>Diseño de nuevas instalaciones industriales</li><li>Expansión de sistemas existentes</li><li>Proyectos de retrofit y modernización</li><li>Instalaciones temporales o modulares</li><li>Cualquier modificación que afecte la distribución eléctrica</li></ul><p>Se aplica a todos los niveles del sistema de potencia.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Capacidad de voltaje</strong><br> El equipo debe coincidir con el voltaje del sistema y los requisitos de aislamiento</p></li><li><p><strong>Capacidad de corriente</strong><br> Debe soportar la carga esperada y el posible crecimiento futuro</p></li><li><p><strong>Capacidad de cortocircuito</strong><br> Debe soportar e interrumpir la corriente de falla disponible</p></li><li><p><strong>Compatibilidad de protección</strong><br> Los dispositivos deben alinearse con la estrategia de coordinación y protección</p></li><li><p><strong>Condiciones ambientales</strong><br> La temperatura, la humedad, el polvo y la ubicación afectan la selección</p></li><li><p><strong>Normas y cumplimiento</strong><br> El equipo debe cumplir con las regulaciones y certificaciones aplicables</p></li><li><p><strong>Mantenimiento y accesibilidad</strong><br> El diseño debe permitir operación y servicio seguros</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>La selección debe considerar las condiciones de operación en el peor caso, no solo los valores nominales</li><li>El equipo subdimensionado es una causa importante de fallas e incidentes de seguridad</li><li>El sobredimensionamiento mejora el margen pero aumenta el costo y puede reducir la eficiencia</li><li>Estandarizar el equipo simplifica el mantenimiento y la gestión de refacciones</li><li>La coordinación temprana entre los equipos de diseño y operación mejora el desempeño a largo plazo</li></ul>',22)])])}const b=i(l,[["render",n]]);export{m as __pageData,b as default};
